'use strict';

/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * Uses a true per-IP sliding window backed by an in-memory timestamp log.
 * Each request records its exact arrival time; on each subsequent request the
 * log is trimmed to only timestamps that fall inside [now - windowMs, now],
 * so the allowed budget always reflects the most recent `windowMs` of real
 * activity — never a fixed calendar interval that resets on a clock tick.
 *
 * ─── NOTE: req.ip behind a reverse proxy ────────────────────────────────────
 * Express derives req.ip from the X-Forwarded-For header ONLY when the app
 * has `app.set('trust proxy', true)` (or a numeric hop-count / CIDR allowlist).
 * Without that setting every request appears to originate from the proxy's
 * loopback address, collapsing all traffic into a single rate-limit bucket.
 * Match the trust-proxy value to your actual deployment topology:
 *
 *   app.set('trust proxy', 1);   // trust the first hop (e.g. Nginx on localhost)
 * ────────────────────────────────────────────────────────────────────────────
 */

/**
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window length in milliseconds.
 * @property {number} [maxRequests=100]  - Max requests allowed inside the window.
 */

/**
 * @typedef {Object} RateLimiter
 * @property {import('express').RequestHandler} middleware
 * @property {() => void} close  - Clears the background cleanup interval so the
 *                                 Node.js process can exit cleanly.
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000;  // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;     // default: 100 req/window

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (typeof maxRequests !== 'number' || maxRequests < 1) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  /**
   * Primary store: IP → sorted array of request timestamps (ms since epoch).
   *
   * Arrays stay in ascending order because requests arrive in time order
   * (we always push to the end).  Expiry trims from the front only, so the
   * hot-path splice is always O(k) where k = expired entries, not O(n).
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ─── Background cleanup ──────────────────────────────────────────────────
  //
  // Every 60 s, evict IPs whose most-recent request is older than `windowMs`.
  // This bounds memory growth for long-lived servers under churn.
  //
  // The per-request trim (below) remains the authoritative algorithm step;
  // the cleanup interval is purely a housekeeping concern.

  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [ip, timestamps] of store) {
      // The array is sorted, so the last element is the most recent timestamp.
      // If even the most recent request has expired, the whole bucket is stale.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        store.delete(ip);
      }
    }
  }, 60_000);

  // Allow the Node.js event loop to exit even if this timer is still pending.
  // `unref()` is a no-op in environments that don't support it (e.g. browsers).
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // ─── Middleware ───────────────────────────────────────────────────────────

  function middleware(req, res, next) {
    const ip          = req.ip ?? req.socket?.remoteAddress ?? 'unknown';
    const now         = Date.now();
    const windowStart = now - windowMs;

    // Retrieve — or lazily create — the timestamp log for this IP.
    let timestamps = store.get(ip);
    if (timestamps === undefined) {
      timestamps = [];
      store.set(ip, timestamps);
    }

    // ── Step 1: trim expired timestamps ────────────────────────────────────
    //
    // Binary-search for the leftmost index whose timestamp is still inside
    // the window (i.e. > windowStart).  Everything before that index is
    // expired and gets spliced off.  Binary search keeps this O(log n) even
    // for bursty IPs with large windows.

    let lo = 0;
    let hi = timestamps.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (timestamps[mid] <= windowStart) {
        lo = mid + 1;
      } else {
        hi = mid;
      }
    }
    if (lo > 0) {
      timestamps.splice(0, lo);
    }

    const currentCount = timestamps.length;

    // ── Step 2: enforce the limit ───────────────────────────────────────────
    if (currentCount >= maxRequests) {
      // The client must wait until the oldest in-window timestamp expires so
      // that one slot opens up.
      const oldestInWindow = timestamps[0];           // array is sorted ↑
      const retryAfterMs   = oldestInWindow + windowMs - now;
      const retryAfterSecs = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSecs));
      return res
        .status(429)
        .json({ error: 'Rate limit exceeded', retryAfter: retryAfterSecs });
    }

    // ── Step 3: record and allow ────────────────────────────────────────────
    //
    // Stamp BEFORE calling next() — concurrent requests on the same event-loop
    // tick are all in-flight simultaneously and must each count toward the
    // budget immediately, not after their handlers complete.
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;

    // Reset = epoch second when the oldest still-valid timestamp will expire,
    // i.e. when at least one slot is guaranteed to open up.
    const resetEpochSecs = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set('X-RateLimit-Limit',     String(maxRequests));
    res.set('X-RateLimit-Remaining', String(remaining));
    res.set('X-RateLimit-Reset',     String(resetEpochSecs));

    next();
  }

  // ─── Public API ───────────────────────────────────────────────────────────

  /** Stops the cleanup interval for graceful shutdown. */
  function close() {
    clearInterval(cleanupTimer);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
